import { getColors } from "./../../Styles/colors";
import styled, { css } from "styled-components";
import { ElementProps } from "./types";
import { Theme } from "../../Theme/types";

export const Container = styled.button<ElementProps>`
  width: 65px;
  height: 50px;
  position: relative;
  background-color: ${(props) => getColors(props.theme).background};
  border: none;
  border: 2px solid cyan;
  direction: rtl;
`;

export const Sun = styled.div<ElementProps>`
  width: 50px;
  height: 50px;
  margin: 0;
  padding: 0;
  border-radius: 25px;
  background-color: ${(props) => getColors(props.theme).background};
  background-color: ${(props) => getColors(props.theme).background};
  position: absolute;
  right: 15px;
  z-index: 1;
  top: 0;

  ${(props) => props.theme === Theme.LIGHT && css(`color: white`)}
`;

export const Moon = styled.div<ElementProps>`
  width: 50px;
  height: 50px;
  margin: 0;
  padding: 0;
  border-radius: 25px;
  background-color: ${(props) => getColors(props.theme).text};
  box-sizing: border-box;
  position: absolute;
  top: 0;
`;
